const payload = $json.body ?? $json;
const message = String(payload.message ?? '').trim();
const context = payload.context ?? {};
const recommendedTitle = String(context.recommended_title ?? '').trim();
const recommendedTags = Array.isArray(context.recommended_tags) ? context.recommended_tags.filter(Boolean) : [];
const why = Array.isArray(context.why_competitors_win) ? context.why_competitors_win.filter(Boolean) : [];
const actions = Array.isArray(context.what_to_implement) ? context.what_to_implement.filter(Boolean) : [];
const pricing = Array.isArray(context.pricing_strategy) ? context.pricing_strategy.filter(Boolean) : [];
const trust = Array.isArray(context.trust_boosters) ? context.trust_boosters.filter(Boolean) : [];
const faqs = Array.isArray(context.faq_recommendations) ? context.faq_recommendations.filter(Boolean) : [];
let reply = 'Use the current market gaps to tighten your gig before changing anything else.';
let suggestions = [];
const lower = message.toLowerCase();
if (lower.includes('title') || lower.includes('headline')) {
  reply = recommendedTitle ? `Your strongest current title option is: ${recommendedTitle}` : 'Run a fresh market compare so the app can generate a stronger title.';
  suggestions = actions.slice(0, 2);
} else if (lower.includes('tag') || lower.includes('keyword')) {
  reply = recommendedTags.length ? `Your current market-aligned tags are: ${recommendedTags.slice(0, 5).join(', ')}.` : 'Run a fresh market compare so the app can generate updated keyword tags.';
  suggestions = actions.slice(0, 2);
} else if (lower.includes('price') || lower.includes('pricing') || lower.includes('package')) {
  reply = pricing[0] || 'Your current pricing needs a fresh compare run before it can be scored against the market anchor.';
  suggestions = pricing.slice(1, 4);
} else if (lower.includes('trust') || lower.includes('review') || lower.includes('proof')) {
  reply = trust[0] || why[0] || 'The clearest visible gap is still proof and review density compared with stronger competitors.';
  suggestions = trust.slice(1, 4);
} else if (lower.includes('faq') || lower.includes('question')) {
  reply = faqs[0] || 'The app has not generated FAQ recommendations yet.';
  suggestions = faqs.slice(1, 4);
} else {
  reply = why[0] || reply;
  suggestions = actions.slice(0, 2);
  if (trust[0]) suggestions.push(trust[0]);
}
return [{ json: { reply, suggestions: suggestions.slice(0, 3) } }];
